8	#include <algorithm>
9	#include <queue>
10	#include <boost/range/adaptor/reversed.hpp>
11	#include <rime/algo/syllabifier.h>
12	#include <rime/dict/corrector.h>
13	#include <rime/dict/prism.h>
14	#include "syllabifier.h"
15	
16	namespace rime {
17	using namespace corrector;
18	
19	using Vertex = pair<size_t, SpellingType>;
20	using VertexQueue =
21	    std::priority_queue<Vertex, vector<Vertex>, std::greater<Vertex>>;
22	
23	// 權重階梯：
24	// 1. 全拼：用戶完整輸入了所有編碼。Penalty = 0
25	// 2. 簡拼：用戶輸入了縮寫，明確希望匹配某個字。Penalty ≈ -2.3
26	// 3. 補全 (Completion)：用戶還沒打完，算法瞎猜的。Penalty ≈ -3.0
27	const double kCompletionPenalty = -2.995732273553991;      // log(0.05)
28	const double kCorrectionCredibility = -4.605170185988091;  // log(0.01)
29	
30	int Syllabifier::BuildSyllableGraph(const string& input,
31	                                    Prism& prism,
32	                                    SyllableGraph* graph) {
33	  if (input.empty())
34	    return 0;
35	
36	  size_t farthest = 0;
37	  VertexQueue queue;
38	  queue.push(Vertex{0, kNormalSpelling});  // start
39	
40	  while (!queue.empty()) {
41	    Vertex vertex(queue.top());
42	    queue.pop();
43	    size_t current_pos = vertex.first;
44	
45	    // record a visit to the vertex
46	    if (graph->vertices.find(current_pos) == graph->vertices.end()) {
47	      graph->vertices.insert(vertex);  // preferred spelling type comes first
48	    } else {
49	      //      graph->vertices[current_pos] =
50	      //          std::min(vertex.second, graph->vertices[current_pos]);
51	      continue;  // discard worse spelling types
52	    }
53	
54	    if (current_pos > farthest)
55	      farthest = current_pos;
56	
57	    // consume leading delimiters
58	    size_t begin_pos = current_pos;
59	    while (begin_pos < input.length() &&
60	           delimiters_.find(input[begin_pos]) != string::npos)
61	      ++begin_pos;
62	    DLOG(INFO) << "current_pos: " << current_pos
63	               << ", begin_pos: " << begin_pos;
64	
65	    // see where we can go by advancing a syllable
66	    vector<Prism::Match> matches;
67	    set<SyllableId> exact_match_syllables;
68	    auto current_input = input.substr(begin_pos);
69	    prism.CommonPrefixSearch(current_input, &matches);
70	    if (corrector_) {
71	      for (auto& m : matches) {
72	        exact_match_syllables.insert(m.value);
73	      }
74	      Corrections corrections;
75	      corrector_->ToleranceSearch(prism, current_input, &corrections, 5);
76	      for (const auto& m : corrections) {
77	        for (auto accessor = prism.QuerySpelling(m.first);
78	             !accessor.exhausted(); accessor.Next()) {
79	          auto props = accessor.properties();
80	          if (props.type == kNormalSpelling && !props.is_correction) {
81	            matches.push_back({m.first, m.second.length});
82	            break;
83	          }
84	        }
85	      }
86	    }
87	
88	    size_t leading_gap = begin_pos - current_pos;
89	    if (!matches.empty()) {
90	      auto& end_vertices(graph->edges[current_pos]);
91	      for (const auto& m : matches) {
92	        if (m.length == 0)
93	          continue;
94	        size_t end_pos = current_pos + leading_gap + m.length;
95	        // consume trailing delimiters
96	        while (end_pos < input.length() &&
97	               delimiters_.find(input[end_pos]) != string::npos)
98	          ++end_pos;
99	        DLOG(INFO) << "end_pos: " << end_pos;
100	        bool matches_input = (current_pos == 0 && end_pos == input.length());
101	        SpellingMap& spellings(end_vertices[end_pos]);
102	        SpellingType end_vertex_type = kInvalidSpelling;
103	        // when spelling algebra is enabled,
104	        // a spelling evaluates to a set of syllables;
105	        // otherwise, it resembles exactly the syllable itself.
106	        SpellingAccessor accessor(prism.QuerySpelling(m.value));
107	        while (!accessor.exhausted()) {
108	          SyllableId syllable_id = accessor.syllable_id();
109	          EdgeProperties props(accessor.properties());
110	          if (strict_spelling_ && matches_input &&
111	              props.type != kNormalSpelling) {
112	            // disqualify fuzzy spelling or abbreviation as single word
113	          } else {
114	            props.end_pos = end_pos;
115	            // add a syllable with properties to the edge's
116	            // spelling-to-syllable map
117	            if (corrector_ && exact_match_syllables.find(m.value) ==
118	                                  exact_match_syllables.end()) {
119	              props.is_correction = true;
120	              props.credibility = kCorrectionCredibility;
121	            }
122	            auto it = spellings.find(syllable_id);
123	            if (it == spellings.end()) {
124	              spellings.insert({syllable_id, props});
125	            } else {
126	              it->second.type = (std::min)(it->second.type, props.type);
127	            }
128	            // let end_vertex_type be the best (smaller) type of spelling
129	            // that ends at the vertex
130	            if (end_vertex_type > props.type && !props.is_correction) {
131	              end_vertex_type = props.type;
132	            }
133	          }
134	          accessor.Next();
135	        }
136	        if (spellings.empty()) {
137	          DLOG(INFO) << "not spelled.";
138	          end_vertices.erase(end_pos);
139	          continue;
140	        }
141	        // find the best common type in a path up to the end vertex
142	        // eg. pinyin "shurfa" has vertex type kNormalSpelling at position 3,
143	        // kAbbreviation at position 4 and kAbbreviation at position 6
144	        if (end_vertex_type < vertex.second) {
145	          end_vertex_type = vertex.second;
146	        }
147	        queue.push(Vertex{end_pos, end_vertex_type});
148	        DLOG(INFO) << "added to syllable graph, edge: [" << current_pos << ", "
149	                   << end_pos << ")";
150	      }
151	    }
152	  }
153	
154	  DLOG(INFO) << "remove stale vertices and edges";
155	  set<int> good;
156	  good.insert(farthest);
157	  // fuzzy spellings are immune to invalidation by normal spellings
158	  SpellingType last_type =
159	      (std::max)(graph->vertices[farthest], kFuzzySpelling);
160	  for (int i = farthest - 1; i >= 0; --i) {
161	    if (graph->vertices.find(i) == graph->vertices.end())
162	      continue;
163	    // remove stale edges
164	    for (auto j = graph->edges[i].begin(); j != graph->edges[i].end();) {
165	      if (good.find(j->first) == good.end()) {
166	        // not connected
167	        graph->edges[i].erase(j++);
168	        continue;
169	      }
170	      // remove disqualified syllables (eg. matching abbreviated spellings)
171	      // when there is a path of more favored type
172	      SpellingType edge_type = kInvalidSpelling;
173	      for (auto k = j->second.begin(); k != j->second.end();) {
174	        if (k->second.is_correction) {
175	          ++k;
176	          continue;  // Don't care correction edges
177	        }
178	        if (k->second.type > last_type) {
179	          j->second.erase(k++);
180	        } else {
181	          if (k->second.type < edge_type)
182	            edge_type = k->second.type;
183	          ++k;
184	        }
185	      }
186	      if (j->second.empty()) {
187	        graph->edges[i].erase(j++);
188	      } else {
189	        if (edge_type < kAbbreviation)
190	          CheckOverlappedSpellings(graph, i, j->first);
191	        ++j;
192	      }
193	    }
194	    if (graph->vertices[i] > last_type || graph->edges[i].empty()) {
195	      DLOG(INFO) << "remove stale vertex at " << i;
196	      graph->vertices.erase(i);
197	      graph->edges.erase(i);
198	      continue;
199	    }
200	    // keep the valid vertex
201	    good.insert(i);
202	  }
203	
204	  if (enable_completion_ && farthest < input.length()) {
205	    DLOG(INFO) << "completion enabled";
206	    const size_t kExpandSearchLimit = 512;
207	    vector<Prism::Match> keys;
208	    prism.ExpandSearch(input.substr(farthest), &keys, kExpandSearchLimit);
209	    if (!keys.empty()) {
210	      size_t current_pos = farthest;
211	      size_t end_pos = input.length();
212	      size_t code_length = end_pos - current_pos;
213	      auto& end_vertices(graph->edges[current_pos]);
214	      auto& spellings(end_vertices[end_pos]);
215	      for (const auto& m : keys) {
216	        if (m.length < code_length)
217	          continue;
218	        // when spelling algebra is enabled,
219	        // a spelling evaluates to a set of syllables;
220	        // otherwise, it resembles exactly the syllable itself.
221	        SpellingAccessor accessor(prism.QuerySpelling(m.value));
222	        while (!accessor.exhausted()) {
223	          SyllableId syllable_id = accessor.syllable_id();
224	          SpellingProperties props = accessor.properties();
225	          if (props.type < kAbbreviation) {
226	            props.type = kCompletion;
227	            props.credibility += kCompletionPenalty;
228	            props.end_pos = end_pos;
229	            // add a syllable with properties to the edge's
230	            // spelling-to-syllable map
231	            spellings.insert({syllable_id, props});
232	          }
233	          accessor.Next();
234	        }
235	      }
236	      if (spellings.empty()) {
237	        DLOG(INFO) << "no completion could be made.";
238	        end_vertices.erase(end_pos);
239	      } else {
240	        DLOG(INFO) << "added to syllable graph, completion: [" << current_pos
241	                   << ", " << end_pos << ")";
242	        farthest = end_pos;
243	      }
244	    }
245	  }
246	
247	  graph->input_length = input.length();
248	  graph->interpreted_length = farthest;
249	  DLOG(INFO) << "input length: " << graph->input_length;
250	  DLOG(INFO) << "syllabified length: " << graph->interpreted_length;
251	
252	  Transpose(graph);
253	
254	  return farthest;
255	}
256	
257	void Syllabifier::CheckOverlappedSpellings(SyllableGraph* graph,
258	                                           size_t start,
259	                                           size_t end) {
260	  if (!graph || graph->edges.find(start) == graph->edges.end())
261	    return;
262	  // if "Z" = "YX", mark the vertex between Y and X an ambiguous syllable joint
263	  auto& y_end_vertices(graph->edges[start]);
264	  // enumerate Ys
265	  for (const auto& y : y_end_vertices) {
266	    size_t joint = y.first;
267	    if (joint >= end)
268	      break;
269	    // test X
270	    if (graph->edges.find(joint) == graph->edges.end())
271	      continue;
272	    auto& x_end_vertices(graph->edges[joint]);
273	    for (auto& x : x_end_vertices) {
274	      if (x.first < end)
275	        continue;
276	      if (x.first == end) {
277	        // discourage syllables at an ambiguous joint
278	        // bad cases include pinyin syllabification "niju'ede"
279	        for (auto& spelling : x.second) {
280	          // 這條邊（X）相對於起點構成歧義
281	          spelling.second.ambiguous_source_positions.insert(start);
282	        }
283	        graph->vertices[joint] = kAmbiguousSpelling;
284	        DLOG(INFO) << "ambiguous syllable joint at position " << joint << ".";
285	      }
286	      break;
287	    }
288	  }
289	}
290	
291	void Syllabifier::Transpose(SyllableGraph* graph) {
292	  for (const auto& start : graph->edges) {
293	    auto& index(graph->indices[start.first]);
294	    for (const auto& end : boost::adaptors::reverse(start.second)) {
295	      for (const auto& spelling : end.second) {
296	        SyllableId syll_id = spelling.first;
297	        index[syll_id].push_back(&spelling.second);
298	      }
299	    }
300	  }
301	}
302	
303	void Syllabifier::EnableCorrection(Corrector* corrector) {
304	  corrector_ = corrector;
305	}
306	
307	}  // namespace rime
308

